   268→		result = OptionDisabled
   269→		arg = arg[1:]
   270→	}
   271→
   272→	optionSplit := strings.SplitN(arg, "=", 2)
   273→	arg = optionSplit[0]
   274→	if len(optionSplit) > 1 {
   275→		if result == OptionDisabled {
   276→			return "", OptionDisabled, fmt.Errorf("invalid boolean format")
   277→		}
   278→
   279→		return ParseKeyValue(lib, arg, optionSplit[1])
   280→	}
   281→
   282→	return "", OptionDisabled, fmt.Errorf("invalid option format")
   283→}
