   402→// enable enables the option `name` with all its dependencies
   403→func (o *IntOptions) enable(name string) {
   404→	if o.Library != nil {
   405→		if _, opt := o.Library.Lookup(name); opt != nil {
   406→			for _, dependency := range opt.Requires {
   407→				o.enable(dependency)
   408→			}
   409→		}
   410→	}
   411→
   412→	o.Opts[name] = OptionEnabled
   413→}
   414→
   415→// set enables the option `name` with all its dependencies, and sets the
   416→// integer level of the option to `value`.
   417→func (o *IntOptions) set(name string, value OptionSetting) {
   418→	o.enable(name)
   419→	o.Opts[name] = value
   420→}
   421→
   422→// disable disables the option `name`. All options which depend on the option
   423→// to be disabled will be disabled. Options which have previously been enabled
   424→// as a dependency will not be automatically disabled.
   425→func (o *IntOptions) disable(name string) {
   426→	o.Opts[name] = OptionDisabled
   427→
   428→	if o.Library != nil {
   429→		// Disable all options which have a dependency on the option
   430→		// that was just disabled
   431→		for key, opt := range *o.Library {
   432→			if opt.RequiresOption(name) && o.Opts[key] != OptionDisabled {
   433→				o.disable(key)
   434→			}
   435→		}
   436→	}
   437→}
