   444→// ApplyValidated takes a configuration map and applies the changes. For an
   445→// option which is changed, the `ChangedFunc` function is called with the
   446→// `data` argument passed in as well. Returns the number of options changed if
   447→// any.
   448→//
   449→// The caller is expected to have validated the configuration options prior to
   450→// calling this function.
   451→func (o *IntOptions) ApplyValidated(n OptionMap, changed ChangedFunc, data interface{}) int {
   452→	changes := make([]changedOptions, 0, len(n))
   453→
   454→	o.optsMU.Lock()
   455→	for k, optVal := range n {
   456→		val, ok := o.Opts[k]
   457→
   458→		if optVal == OptionDisabled {
   459→			/* Only disable if enabled already */
   460→			if ok && val != OptionDisabled {
   461→				o.disable(k)
   462→				changes = append(changes, changedOptions{key: k, value: optVal})
   463→			}
   464→		} else {
   465→			/* Only enable if not enabled already */
   466→			if !ok || val == OptionDisabled {
   467→				o.set(k, optVal)
   468→				changes = append(changes, changedOptions{key: k, value: optVal})
   469→			}
   470→		}
   471→	}
   472→	o.optsMU.Unlock()
   473→
   474→	for _, change := range changes {
   475→		changed(change.key, change.value, data)
   476→	}
   477→
   478→	return len(changes)
   479→}
